class CATEEstimator(BaseCATEEstimator):
    """Inverse-Variance Doubly Robust (IV-DR) Learner."""

    def __init__(self):
        self._cate_model = None

    def _get_y_model(self):
        return GradientBoostingRegressor(
            n_estimators=200, max_depth=4, learning_rate=0.05,
            min_samples_leaf=20, subsample=0.8, random_state=42
        )

    def _get_t_model(self):
        return GradientBoostingClassifier(
            n_estimators=200, max_depth=3, learning_rate=0.05,
            min_samples_leaf=20, subsample=0.8, random_state=42
        )

    def _get_cate_model(self):
        return GradientBoostingRegressor(
            n_estimators=300, max_depth=4, learning_rate=0.05,
            min_samples_leaf=15, subsample=0.8, random_state=42
        )

    def fit(self, X, T, Y):
        n = len(Y)
        kf = KFold(n_splits=5, shuffle=True, random_state=42)
        mu0_hat = np.zeros(n)
        mu1_hat = np.zeros(n)
        e_hat = np.zeros(n)

        for tr_idx, val_idx in kf.split(X):
            X_tr, T_tr, Y_tr = X[tr_idx], T[tr_idx], Y[tr_idx]

            m0 = self._get_y_model()
            if (T_tr == 0).sum() > 5:
                m0.fit(X_tr[T_tr == 0], Y_tr[T_tr == 0])
                mu0_hat[val_idx] = m0.predict(X[val_idx])
            else:
                mu0_hat[val_idx] = Y_tr.mean()

            m1 = self._get_y_model()
            if (T_tr == 1).sum() > 5:
                m1.fit(X_tr[T_tr == 1], Y_tr[T_tr == 1])
                mu1_hat[val_idx] = m1.predict(X[val_idx])
            else:
                mu1_hat[val_idx] = Y_tr.mean()

            mt = self._get_t_model()
            mt.fit(X_tr, T_tr)
            e_hat[val_idx] = mt.predict_proba(X[val_idx])[:, 1]

        e_hat = np.clip(e_hat, 0.05, 0.95)

        phi = np.zeros(n)
        weights = np.zeros(n)
        m1_mask = T == 1
        m0_mask = T == 0

        phi[m1_mask] = mu1_hat[m1_mask] - mu0_hat[m1_mask] + (Y[m1_mask] - mu1_hat[m1_mask]) / e_hat[m1_mask]
        weights[m1_mask] = e_hat[m1_mask] ** 2

        phi[m0_mask] = mu1_hat[m0_mask] - mu0_hat[m0_mask] - (Y[m0_mask] - mu0_hat[m0_mask]) / (1 - e_hat[m0_mask])
        weights[m0_mask] = (1 - e_hat[m0_mask]) ** 2

        q = np.percentile(np.abs(phi), 98)
        phi = np.clip(phi, -q, q)

        weights = weights + 0.01
        weights = weights / weights.mean()

        self._cate_model = self._get_cate_model()
        self._cate_model.fit(X, phi, sample_weight=weights)
        return self

    def predict(self, X):
        return self._cate_model.predict(X)

